import React, { useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import PaymentModule from 'payment-module';

const App = () => {
  const [paymentMethod, setPaymentMethod] = useState(null);
  const [transactionId, setTransactionId] = useState('');

  // Initialize the payment module with your payment provider's credentials
  const paymentModule = new PaymentModule({
    apiKey: 'YOUR_API_KEY',
    merchantId: 'YOUR_MERCHANT_ID',
    sandboxMode: true, // set to false for production mode
  });

  const handleSubmit = async () => {
    try {
      const result = await paymentModule.initiateTransaction({
        amount: 10.99,
        currency: 'USD',
        description: 'In-app purchase',
        referenceId: transactionId, // unique id for this transaction
      });

      if (result.status === 'success') {
        console.log('Transaction initiated successfully');
        setPaymentMethod(result.paymentMethod);
        setTransactionId(result.transactionId);
      } else {
        console.error('Failed to initiate transaction', result.message);
      }
    } catch (e) {
      console.error('Error initiating transaction', e);
    }
  };

  return (
    <View style={styles.container}>
      <Text>Initiate Payment</Text>
      <Button title="Pay $10.99" onPress={handleSubmit} />
      {paymentMethod && <Text>{paymentMethod}</Text>}
      {transactionId && <Text>{transactionId}</Text>}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

export default App;